import { useState } from 'react';

function LikeButton() {
  const [count, setCount] = useState(0);

  function handleLike() {
    setCount(count + 1);
  }

  return (
    <div>
      <button onClick={handleLike}>
        ♥ {count} {count === 1 ? 'Like' : 'Likes'}
      </button>
    </div>
  );
}

export default LikeButton;
